                            }`}
                            onClick={() => filterNews('events')}
                        >
                            <span className="material-icons mr-2 text-sm">event</span>
                            {t('newsPage.filters.events')}
                        </button>
                        <button 
                            className={`inline-flex items-center px-6 py-3 rounded-full font-medium transition-all duration-300 ${
                                activeCategory === 'announcements' 
                                    ? 'bg-purple-600 text-white shadow-lg shadow-purple-600/30' 
                                    : 'bg-gray-100 text-gray-700 hover:bg-gray-200'
