                                    <span className="text-gray-500">{t('newsPage.items.techSymposium.date')}</span>
                                </div>
                                <h2 className="text-3xl lg:text-4xl font-bold text-gray-900 mb-6">
                                    {t('newsPage.featured.title')}
                                </h2>
                                <p className="text-lg text-gray-600 mb-8 leading-relaxed">
                                    {t('newsPage.featured.excerpt')}
                                </p>
                                <div className="flex flex-col sm:flex-row gap-4">
                                    <a 
                                        href="/news/tech-symposium" 
                                        className="inline-flex items-center justify-center px-6 py-3 bg-blue-600 text-white rounded-lg font-semibold hover:bg-blue-700 transition-colors"
                                    >
                                        <span className="material-icons mr-2">read_more</span>
                                        {t('newsPage.buttons.learnMore')}
                                    </a>
                                    <a 
                                        href="/events/register" 
                                        className="inline-flex items-center justify-center px-6 py-3 border-2 border-blue-600 text-blue-600 rounded-lg font-semibold hover:bg-blue-50 transition-colors"
                                    >
                                        <span className="material-icons mr-2">how_to_reg</span>
                                        {t('newsPage.buttons.registerNow')}
                                    </a>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </section>

            {/* News Grid */}
            <section className="py-16 bg-gray-50">
                <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
                    <div className="text-center mb-12">
                        <h2 className="text-3xl lg:text-4xl font-bold text-gray-900 mb-4">
                            {getSectionTitle()}
                        </h2>
                        <p className="text-lg text-gray-600">
                            {filteredNews.length} {filteredNews.length === 1 ? t('newsPage.itemCount.singular') : t('newsPage.itemCount.plural')}
                        </p>
                    </div>

                    {filteredNews.length > 0 ? (
                        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                            {filteredNews.map((item, index) => (
                                <div 
                                    key={item.id}
                                    className="bg-white rounded-2xl shadow-lg hover:shadow-xl transition-all duration-300 hover:-translate-y-2 overflow-hidden group news-item"
                                    style={{ animationDelay: `${index * 0.1}s` }}
                                >
                                    <div className="relative">
                                        {!loadedVideos[item.id] && (
                                            <div className="absolute inset-0 bg-gray-200 flex items-center justify-center z-10">
                                                <div className="flex flex-col items-center">
                                                    <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600 mb-2"></div>
                                                    <span className="text-sm text-gray-500">{t('newsPage.loading')}</span>
                                                </div>
                                            </div>
                                        )}
                                        <video 
                                            controls 
                                            autoPlay 
                                            muted 
                                            loop
                                            className={`w-full h-48 object-cover transition-opacity duration-300 ${loadedVideos[item.id] ? 'opacity-100' : 'opacity-0'}`}
                                            onLoadedData={() => handleVideoLoad(item.id)}
                                        >
                                            <source src={item.videoSrc} type="video/mp4" />
                                            {t('newsPage.videoNotSupported')}
                                        </video>
                                    </div>

                                    <div className="p-6">
                                        <div className="flex items-center justify-between mb-4">
                                            <span className={`inline-flex items-center px-3 py-1 rounded-full text-sm font-medium ${
                                                item.category === 'events' ? 'bg-green-100 text-green-800' :
                                                item.category === 'announcements' ? 'bg-purple-100 text-purple-800' :
                                                'bg-orange-100 text-orange-800'
                                            }`}>
                                                <span className="material-icons mr-1 text-sm">
                                                    {getCategoryIcon(item.category)}
                                                </span>
                                                {getCategoryLabel(item.category)}
                                            </span>
                                            <span className="text-sm text-gray-500">{item.date}</span>
                                        </div>

                                        <h3 className="text-xl font-bold text-gray-900 mb-3 group-hover:text-blue-600 transition-colors">
                                            {item.title}
                                        </h3>

                                        <p className="text-gray-600 mb-4 line-clamp-3">
                                            {item.excerpt}
                                        </p>

                                        <a 
                                            href={item.fullContent} 
                                            className="inline-flex items-center text-blue-600 font-semibold hover:text-blue-800 transition-colors"
                                        >
                                            <span className="material-icons mr-1 text-sm">read_more</span>
                                            {t('newsPage.buttons.readMore')}
                                        </a>
                                    </div>
                                </div>
                            ))}
                        </div>
                    ) : (
                        <div className="text-center py-16">
                            <span className="material-icons text-6xl text-gray-400 mb-4">search_off</span>
                            <h3 className="text-2xl font-bold text-gray-500 mb-2">
                                {t('newsPage.noResults.title')} {activeCategory === 'all' ? t('newsPage.noResults.items') : getCategoryLabel(activeCategory)}
                            </h3>
                            <p className="text-gray-400">{t('newsPage.noResults.description')}</p>
                        </div>
                    )}
                </div>
            </section>
        </div>
    );
};

export default NewsPage;
